(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"score-percent",fields:[{"key":"score","label":"받은 점수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"max","label":"만점","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.score),m=Number(x.max);if(![s,m].every(Number.isFinite)||m===0)return{error:"만점은 0이 아닌 값이어야 합니다."};return{value:s/m*100};},format:function(r,api){return api.resultCard("점수 백분율",api.formatNumber(r.value,6)+"%","");}},{id:"weighted-grade",fields:[{"key":"s1","label":"점수 1","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"w1","label":"가중치 1","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"s2","label":"점수 2","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"w2","label":"가중치 2","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.s1),b=Number(x.w1),c=Number(x.s2),d=Number(x.w2),sum=b+d;if(![a,b,c,d].every(Number.isFinite)||sum===0)return{error:"가중치 합은 0이 아니어야 합니다."};return{value:(a*b+c*d)/sum};},format:function(r,api){return api.resultCard("가중 평균 점수",api.formatNumber(r.value,10)+"","");}},{id:"target-final-score",fields:[{"key":"current","label":"현재 평균 점수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"finalWeight","label":"기말 반영비율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"target","label":"목표 최종점수","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var c=Number(x.current),w=Number(x.finalWeight)/100,t=Number(x.target);if(![c,w,t].every(Number.isFinite)||w<=0||w>1)return{error:"기말 반영비율은 0% 초과 100% 이하로 입력해 주세요."};return{value:(t-c*(1-w))/w};},format:function(r,api){return api.resultCard("필요 기말 점수",api.formatNumber(r.value,10)+"","");}},{id:"gpa-simple",fields:[{"key":"values","label":"평점 목록","type":"textarea","placeholder":"예: 4.0, 3.5, 4.5","default":"","options":[],"raw":true}],hint:"",compute:function(x){var a=String(x.values||'').split(/[,\s]+/).filter(Boolean).map(Number);if(!a.length||a.some(function(v){return !Number.isFinite(v);} ))return{error:"평점을 숫자로 입력해 주세요."};return{value:a.reduce(function(s,v){return s+v;},0)/a.length};},format:function(r,api){return api.resultCard("평균 평점",api.formatNumber(r.value,10)+"","");}},{id:"gpa-weighted",fields:[{"key":"g1","label":"과목1 평점","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"c1","label":"과목1 학점","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"g2","label":"과목2 평점","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"c2","label":"과목2 학점","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var g1=Number(x.g1),c1=Number(x.c1),g2=Number(x.g2),c2=Number(x.c2),sum=c1+c2;if(![g1,c1,g2,c2].every(Number.isFinite)||sum===0)return{error:"학점 합은 0이 아니어야 합니다."};return{value:(g1*c1+g2*c2)/sum};},format:function(r,api){return api.resultCard("가중 GPA",api.formatNumber(r.value,10)+"","");}},{id:"attendance-rate",fields:[{"key":"attended","label":"출석 수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"total","label":"전체 수업 수","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.attended),t=Number(x.total);if(![a,t].every(Number.isFinite)||t===0)return{error:"전체 수업 수는 0이 아니어야 합니다."};return{value:a/t*100};},format:function(r,api){return api.resultCard("출석률",api.formatNumber(r.value,6)+"%","");}},{id:"required-average",fields:[{"key":"target","label":"목표 총점","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"current","label":"현재 누적점수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"remaining","label":"남은 시험 수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var t=Number(x.target),c=Number(x.current),r=Number(x.remaining);if(![t,c,r].every(Number.isFinite)||!Number.isInteger(r)||r<=0)return{error:"남은 시험 수는 1 이상이어야 합니다."};return{value:(t-c)/r};},format:function(r,api){return api.resultCard("필요 평균 점수",api.formatNumber(r.value,10)+"","");}},{id:"wrong-answer-rate",fields:[{"key":"wrong","label":"틀린 문제 수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"total","label":"전체 문제 수","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var w=Number(x.wrong),t=Number(x.total);if(![w,t].every(Number.isFinite)||t===0)return{error:"전체 문제 수는 0이 아니어야 합니다."};return{value:w/t*100};},format:function(r,api){return api.resultCard("오답률",api.formatNumber(r.value,6)+"%","");}},{id:"study-hours-average",fields:[{"key":"hours","label":"총 공부시간","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"days","label":"일수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var h=Number(x.hours),d=Number(x.days);if(!Number.isFinite(h)||!Number.isInteger(d)||d<=0)return{error:"일수는 1일 이상이어야 합니다."};return{value:h/d};},format:function(r,api){return api.resultCard("하루 평균 공부시간",api.formatNumber(r.value,10)+" 시간","");}},{id:"rank-percent",fields:[{"key":"rank","label":"등수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"total","label":"전체 인원","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var r=Number(x.rank),t=Number(x.total);if(![r,t].every(Number.isFinite)||t<=0||r<=0)return{error:"등수와 전체 인원을 0보다 크게 입력해 주세요."};return{value:r/t*100};},format:function(r,api){return api.resultCard("상위 비율",api.formatNumber(r.value,6)+"%","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);